  ('social-worker-moex-05184', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據Rothman社區工作三大模式的比較，下列敘述何者正確？', '["社會計畫模式的目標為社區能力及整合", "地區發展模式中工作者的角色為倡議者", "社會行動模式中案主的角色為積極倡議者", "社會計畫模式關心的問題在於社區實質問題的解決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05185', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關「女性與社區」的敘述，下列何者錯誤？', '["在社區生活中，女性通常扮演後勤、資源補給的角色", "相較於男性而言，女性花更多的時間在社區事務上，因為她們經常扮演帶著孩子與其他女性及 孩子互動的角色，尤其是參與學齡前或學校活動", "社區是建構性別劣勢的途徑之一，限制了女性的某些生活機會，也常認為女性是初級照顧者、 依賴國家福利與男性的角色", "社區是所有人生活的場域，男性與女性都能有相似的社區經驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05186', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '醫務社會工作者協助因為受到工業區排放污水、廢氣而罹癌之病友家屬集結起來，一起走上街頭 向廠商抗爭，以爭取後續醫療賠償的權益，此種社區工作方法為下列何者？', '["評估社區績效", "社會行動模式", "規劃社區方案", "社區計畫模式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05187', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「團體領導者使用情感轉移與情感反轉移的現象，協助成員探討過去的行為模式，以及這些模式 與現在行為模式的關聯，以處理未被解決的衝突。」以上概念，屬於下列那種理論的範疇？', '["學習理論", "敘事與結構理論", "場域理論", "心理動力理論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05188', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於「任務中心取向」實務運用限制的敘述，下列何者錯誤？', '["對某些案主而言，任務中心取向強調短期處遇，但有無足夠時間允許社會工作者與案主一起蒐 集必要資訊，也是一項考驗", "任務中心取向未明確指出那一類的任務特別適合用於何種案主或何種類型的問題", "任務中心取向有其界定問題的方法，因此在實務運用上，較不適合結合多種理論取向", "任務中心取向不適用於無能力界定問題、無法治癒之慢性精神疾病等案主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05189', 'social-worker', 'social-worker-moex-107-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社區中進行資源整合，下列那一項概念錯誤？', '["未有足夠的資源也可以整合", "要有整合者", "整合就是合作朝向某個目標努力", "整合就是進行工作重分配、資源重配置的活動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "fe104a5d002b", "answer_pdf_sha1": "78b9518a750b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
